class FfiConverterBoolean: FfiConverter<bool, sbyte> {
    public static FfiConverterBoolean INSTANCE = new FfiConverterBoolean();

    public override bool Lift(sbyte value) {
        return value != 0;
    }

    public override bool Read(BigEndianStream stream) {
        return Lift(stream.ReadSByte());
    }

    public override sbyte Lower(bool value) {
        return value ? (sbyte)1 : (sbyte)0;
    }

    public override int AllocationSize(bool value) {
        return (sbyte)1;
    }

    public override void Write(bool value, BigEndianStream stream) {
        stream.WriteSByte(Lower(value));
    }
}



class FfiConverterString: FfiConverter<string, RustBuffer> {
    public static FfiConverterString INSTANCE = new FfiConverterString();

    // Note: we don't inherit from FfiConverterRustBuffer, because we use a
    // special encoding when lowering/lifting.  We can use `RustBuffer.len` to
    // store our length and avoid writing it out to the buffer.
    public override string Lift(RustBuffer value) {
        try {
            var bytes = value.AsStream().ReadBytes(Convert.ToInt32(value.len));
            return System.Text.Encoding.UTF8.GetString(bytes);
        } finally {
            RustBuffer.Free(value);
        }
    }

    public override string Read(BigEndianStream stream) {
        var length = stream.ReadInt();
        var bytes = stream.ReadBytes(length);
        return System.Text.Encoding.UTF8.GetString(bytes);
    }

    public override RustBuffer Lower(string value) {
        var bytes = System.Text.Encoding.UTF8.GetBytes(value);
        var rbuf = RustBuffer.Alloc(bytes.Length);
        rbuf.AsWriteableStream().WriteBytes(bytes);
        return rbuf;
    }

    // TODO(CS)
    // We aren't sure exactly how many bytes our string will be once it's UTF-8
    // encoded.  Allocate 3 bytes per unicode codepoint which will always be
    // enough.
    public override int AllocationSize(string value) {
        const int sizeForLength = 4;
        var sizeForString = System.Text.Encoding.UTF8.GetByteCount(value);
        return sizeForLength + sizeForString;
    }

    public override void Write(string value, BigEndianStream stream) {
        var bytes = System.Text.Encoding.UTF8.GetBytes(value);
        stream.WriteInt(bytes.Length);
        stream.WriteBytes(bytes);
    }
}





/// <summary>
/// Where this event came.
/// </summary>
public enum EventItemOrigin: int {
    /// <summary>
    /// The event was created locally.
    /// </summary>
    Local,
    /// <summary>
    /// The event came from a sync response.
    /// </summary>
    Sync,
    /// <summary>
    /// The event came from pagination.
    /// </summary>
    Pagination,
    /// <summary>
    /// The event came from a cache.
    /// </summary>
    Cache
}

class FfiConverterTypeEventItemOrigin: FfiConverterRustBuffer<EventItemOrigin> {
    public static FfiConverterTypeEventItemOrigin INSTANCE = new FfiConverterTypeEventItemOrigin();

    public override EventItemOrigin Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return EventItemOrigin.Local;
            case 2: return EventItemOrigin.Sync;
            case 3: return EventItemOrigin.Pagination;
            case 4: return EventItemOrigin.Cache;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeEventItemOrigin.Read()", value));
        }
    }

    public override int AllocationSize(EventItemOrigin value) {
        return 4;
    }

    public override void Write(EventItemOrigin value, BigEndianStream stream) {
        switch (value) {
            case EventItemOrigin.Local: stream.WriteInt(1); break;
            case EventItemOrigin.Sync: stream.WriteInt(2); break;
            case EventItemOrigin.Pagination: stream.WriteInt(3); break;
            case EventItemOrigin.Cache: stream.WriteInt(4); break;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeEventItemOrigin.Write()", value));
        }
    }
}







public enum LatestEventValueLocalState: int {
    IsSending,
    HasBeenSent,
    CannotBeSent
}

class FfiConverterTypeLatestEventValueLocalState: FfiConverterRustBuffer<LatestEventValueLocalState> {
    public static FfiConverterTypeLatestEventValueLocalState INSTANCE = new FfiConverterTypeLatestEventValueLocalState();

    public override LatestEventValueLocalState Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return LatestEventValueLocalState.IsSending;
            case 2: return LatestEventValueLocalState.HasBeenSent;
            case 3: return LatestEventValueLocalState.CannotBeSent;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeLatestEventValueLocalState.Read()", value));
        }
    }

    public override int AllocationSize(LatestEventValueLocalState value) {
        return 4;
    }

    public override void Write(LatestEventValueLocalState value, BigEndianStream stream) {
        switch (value) {
            case LatestEventValueLocalState.IsSending: stream.WriteInt(1); break;
            case LatestEventValueLocalState.HasBeenSent: stream.WriteInt(2); break;
            case LatestEventValueLocalState.CannotBeSent: stream.WriteInt(3); break;
            default: throw new publicException(String.Format("invalid enum value '{0}' in FfiConverterTypeLatestEventValueLocalState.Write()", value));
        }
    }
}







/// <summary>
/// The type of change between the previous and current pinned events.
/// </summary>
public enum RoomPinnedEventsChange: int {
    /// <summary>
    /// Only new event ids were added.
    /// </summary>
    Added,
    /// <summary>
    /// Only event ids were removed.
    /// </summary>
    Removed,
    /// <summary>
    /// Some change other than only adding or only removing ids happened.
    /// </summary>
